const data = $input.first().json;

const city = data.name;
const country = data.sys.country;
const temp = Math.round(data.main.temp);
const feelsLike = Math.round(data.main.feels_like);
const tempMin = Math.round(data.main.temp_min);
const tempMax = Math.round(data.main.temp_max);
const humidity = data.main.humidity;
const description = data.weather[0].description;
const windSpeed = data.wind.speed;

// Pick an emoji based on weather condition
const conditionId = data.weather[0].id;
let weatherEmoji = '🌤';
if (conditionId >= 200 && conditionId < 300) weatherEmoji = '⛈';
else if (conditionId >= 300 && conditionId < 400) weatherEmoji = '🌦';
else if (conditionId >= 500 && conditionId < 600) weatherEmoji = '🌧';
else if (conditionId >= 600 && conditionId < 700) weatherEmoji = '❄️';
else if (conditionId >= 700 && conditionId < 800) weatherEmoji = '🌫';
else if (conditionId === 800) weatherEmoji = '☀️';
else if (conditionId > 800) weatherEmoji = '☁️';

const today = new Date().toLocaleDateString('en-IN', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

const message = `${weatherEmoji} *Morning Weather Report*
📅 ${today}
📍 ${city}, ${country}

🌡 *Temperature:* ${temp}°C (Feels like ${feelsLike}°C)
🔼 High: ${tempMax}°C  🔽 Low: ${tempMin}°C
💧 *Humidity:* ${humidity}%
💨 *Wind:* ${windSpeed} m/s
🌤 *Condition:* ${description.charAt(0).toUpperCase() + description.slice(1)}

_Have a great day! 🙌_`;

return [{ json: { message } }];
